 1→use tc24r_error::CompileError;
 2→use tc24r_span::Span;
 3→use tc24r_token::{Token, TokenKind};
 4→
 5→/// Tokenises a source string into a sequence of tokens.
 6→pub struct Lexer<'a> {
 7→    pub(crate) source: &'a [u8],
 8→    pub(crate) pos: usize,
 9→}
10→
11→impl<'a> Lexer<'a> {
12→    pub fn new(source: &'a str) -> Self {
13→        Self {
14→            source: source.as_bytes(),
15→            pos: 0,
16→        }
17→    }
18→
19→    pub fn tokenize(&mut self) -> Result<Vec<Token>, CompileError> {
20→        let mut tokens = Vec::new();
21→        loop {
22→            self.skip_whitespace_and_comments();
23→            if self.pos >= self.source.len() {
24→                tokens.push(Token {
25→                    kind: TokenKind::Eof,
26→                    span: Span::new(self.pos, 0),
27→                });
28→                break;
29→            }
30→            tokens.push(self.next_token()?);
31→        }
32→        Ok(tokens)
33→    }
34→
35→    pub(crate) fn skip_whitespace_and_comments(&mut self) {
36→        loop {
37→            self.skip_whitespace();
38→            if !self.skip_comment() {
39→                break;
40→            }
41→        }
42→    }
43→
44→    fn skip_whitespace(&mut self) {
45→        while self.pos < self.source.len() && self.source[self.pos].is_ascii_whitespace() {
46→            self.pos += 1;
47→        }
48→    }
49→
50→    fn skip_comment(&mut self) -> bool {
51→        if self.pos + 1 >= self.source.len() {
52→            return false;
53→        }
54→        if self.source[self.pos] == b'/' && self.source[self.pos + 1] == b'/' {
55→            self.pos += 2;
56→            while self.pos < self.source.len() && self.source[self.pos] != b'\n' {
57→                self.pos += 1;
58→            }
59→            return true;
60→        }
61→        if self.source[self.pos] == b'/' && self.source[self.pos + 1] == b'*' {
62→            self.pos += 2;
63→            while self.pos + 1 < self.source.len() {
64→                if self.source[self.pos] == b'*' && self.source[self.pos + 1] == b'/' {
65→                    self.pos += 2;
66→                    return true;
67→                }
68→                self.pos += 1;
69→            }
70→            self.pos = self.source.len();
71→            return true;
72→        }
73→        false
74→    }
75→
76→    pub(crate) fn peek_char(&self) -> Option<u8> {
77→        self.source.get(self.pos + 1).copied()
78→    }
79→
80→    pub(crate) fn peek_char_at(&self, offset: usize) -> Option<u8> {
81→        self.source.get(self.pos + offset).copied()
82→    }
83→}
