 1→//! tc24r.
 2→//!
 3→//! Supports:
 4→//! - `#define NAME value` constant substitution
 5→//! - `#include "file.h"` (relative to source directory)
 6→//! - `#include <file.h>` (search system include paths)
 7→//! - `#pragma once` (skip file if already included)
 8→
 9→mod conditional;
10→mod func_args;
11→mod func_macro;
12→mod func_subst;
13→mod include;
14→mod preprocess;
15→mod substitute;
16→
17→pub use func_macro::FuncMacro;
18→pub use preprocess::preprocess;
19→pub(crate) use preprocess::{Context, process_text};
20→

  1→use std::collections::{HashMap, HashSet};
  2→use std::path::Path;
  3→
  4→use crate::conditional::{self, CondStack};
  5→use crate::func_macro::{self, FuncMacro};
  6→use crate::include;
  7→use crate::substitute;
  8→
  9→/// Preprocess source text with optional include support.
 10→///
 11→/// - `source_dir`: directory for resolving `#include "..."` (None disables)
 12→/// - `system_paths`: directories for resolving `#include <...>`
 13→pub fn preprocess(source: &str, source_dir: Option<&Path>, system_paths: &[&Path]) -> String {
 14→    let mut ctx = Context {
 15→        defines: HashMap::new(),
 16→        func_macros: HashMap::new(),
 17→        included: HashSet::new(),
 18→        source_dir: source_dir.map(Path::to_path_buf),
 19→        system_paths: system_paths.iter().map(|p| p.to_path_buf()).collect(),
 20→        cond_stack: CondStack::new(),
 21→    };
 22→    process_text(source, &mut ctx)
 23→}
 24→
 25→pub(crate) struct Context {
 26→    pub defines: HashMap<String, String>,
 27→    pub func_macros: HashMap<String, FuncMacro>,
 28→    pub included: HashSet<std::path::PathBuf>,
 29→    pub source_dir: Option<std::path::PathBuf>,
 30→    pub system_paths: Vec<std::path::PathBuf>,
 31→    pub cond_stack: CondStack,
 32→}
 33→
 34→pub(crate) fn process_text(source: &str, ctx: &mut Context) -> String {
 35→    // Join lines ending with backslash (line continuation)
 36→    let joined = join_continued_lines(source);
 37→    let mut output = String::new();
 38→    for line in joined.lines() {
 39→        process_line(line, ctx, &mut output);
 40→    }
 41→    output
 42→}
 43→
 44→/// Join lines ending with `\` (backslash-newline continuation).
 45→fn join_continued_lines(source: &str) -> String {
 46→    let mut result = String::with_capacity(source.len());
 47→    let mut continuation = false;
 48→    for line in source.lines() {
 49→        if continuation {
 50→            // Append to previous line (no newline between)
 51→        } else if !result.is_empty() {
 52→            result.push('\n');
 53→        }
 54→        if line.ends_with('\\') {
 55→            result.push_str(&line[..line.len() - 1]);
 56→            continuation = true;
 57→        } else {
 58→            result.push_str(line);
 59→            continuation = false;
 60→        }
 61→    }
 62→    result
 63→}
 64→
 65→fn process_line(line: &str, ctx: &mut Context, output: &mut String) {
 66→    let trimmed = line.trim_start();
 67→
 68→    // Conditional directives are always processed, even in skipped blocks
 69→    if let Some(rest) = strip_directive(trimmed, "#if ") {
 70→        let cond = conditional::eval_condition(rest, &ctx.defines, &ctx.func_macros);
 71→        ctx.cond_stack.push_if(cond);
 72→        return;
 73→    }
 74→    if let Some(rest) = strip_directive(trimmed, "#ifdef ") {
 75→        let name = rest.trim();
 76→        let defined = ctx.defines.contains_key(name) || ctx.func_macros.contains_key(name);
 77→        ctx.cond_stack.push_if(defined);
 78→        return;
 79→    }
 80→    if let Some(rest) = strip_directive(trimmed, "#ifndef ") {
 81→        let name = rest.trim();
 82→        let defined = ctx.defines.contains_key(name) || ctx.func_macros.contains_key(name);
 83→        ctx.cond_stack.push_if(!defined);
 84→        return;
 85→    }
 86→    if let Some(rest) = strip_directive(trimmed, "#elif ") {
 87→        let cond = conditional::eval_condition(rest, &ctx.defines, &ctx.func_macros);
 88→        ctx.cond_stack.handle_elif(cond);
 89→        return;
 90→    }
 91→    if trimmed_matches(trimmed, "#else") {
 92→        ctx.cond_stack.handle_else();
 93→        return;
 94→    }
 95→    if trimmed_matches(trimmed, "#endif") {
 96→        ctx.cond_stack.pop();
 97→        return;
 98→    }
 99→
100→    // Skip all content in inactive conditional blocks
101→    if !ctx.cond_stack.is_active() {
102→        return;
103→    }
104→
105→    // Regular directives (only processed when active)
106→    if let Some(rest) = trimmed.strip_prefix("#define ") {
107→        handle_define(rest, ctx);
108→    } else if let Some(rest) = strip_directive(trimmed, "#undef ") {
109→        let name = rest.trim();
110→        ctx.defines.remove(name);
111→        ctx.func_macros.remove(name);
112→    } else if trimmed.starts_with("#include ") {
113→        include::handle_include(trimmed, ctx, output);
114→    } else if trimmed == "#pragma once" {
115→        // Handled at include time -- no output
116→    } else if trimmed.starts_with('#') && !trimmed.starts_with("#define") {
117→        // Unknown directive (e.g. #line, # nnn "file") — skip silently
118→    } else {
119→        let expanded = substitute::expand_line(line, &ctx.defines, &ctx.func_macros);
120→        output.push_str(&expanded);
121→        output.push('\n');
122→    }
123→}
124→
125→/// Strip a directive prefix, handling optional whitespace after `#`.
126→/// e.g. `#  if 1` matches prefix `#if ` and returns `1`.
127→fn strip_directive<'a>(trimmed: &'a str, prefix: &str) -> Option<&'a str> {
128→    // Try exact match first
129→    if let Some(rest) = trimmed.strip_prefix(prefix) {
130→        return Some(rest);
131→    }
132→    // Try with whitespace after #: "# if" or "#  if"
133→    if !trimmed.starts_with('#') {
134→        return None;
135→    }
136→    let after_hash = trimmed[1..].trim_start();
137→    let keyword = &prefix[1..]; // "if ", "ifdef ", etc.
138→    after_hash.strip_prefix(keyword)
139→}
140→
141→/// Check if trimmed line matches a standalone directive (e.g. #else, #endif).
142→fn trimmed_matches(trimmed: &str, directive: &str) -> bool {
143→    if trimmed == directive {
144→        return true;
145→    }
146→    // Handle "# else", "#  endif", etc.
147→    if !trimmed.starts_with('#') {
148→        return false;
149→    }
150→    let after_hash = trimmed[1..].trim_start();

