 3→/// A C type.
 4→#[derive(Debug, Clone, PartialEq)]
 5→pub enum Type {
 6→    Char,
 7→    Int,
 8→    UnsignedInt,
 9→    Void,
10→    Ptr(Box<Type>),
11→    /// Fixed-size array: element type and count.
12→    Array(Box<Type>, usize),
13→    /// Struct type with optional tag name and members.
14→    Struct {
15→        tag: Option<String>,
16→        members: Vec<StructMember>,
17→        total_size: i32,
18→    },
19→}
20→
21→/// A struct member with name, type, and byte offset from struct base.
22→#[derive(Debug, Clone, PartialEq)]
23→pub struct StructMember {
24→    pub name: String,
25→    pub ty: Type,
26→    pub offset: i32,
27→}
28→
29→impl Type {
30→    /// Size in bytes for this type.
31→    pub fn size(&self) -> i32 {
32→        match self {
33→            Type::Char => 1,
34→            Type::Int | Type::UnsignedInt | Type::Void | Type::Ptr(_) => 3,
35→            Type::Array(elem, count) => elem.size() * (*count as i32),
36→            Type::Struct { total_size, .. } => *total_size,
37→        }
38→    }
39→
40→    /// Element type for arrays and pointers.
41→    pub fn element_type(&self) -> Option<&Type> {
42→        match self {
43→            Type::Ptr(inner) | Type::Array(inner, _) => Some(inner),
44→            _ => None,
45→        }
46→    }
47→
48→    /// Look up a struct member by name.
49→    pub fn find_member(&self, name: &str) -> Option<&StructMember> {
50→        match self {
51→            Type::Struct { members, .. } => members.iter().find(|m| m.name == name),
52→            _ => None,
53→        }
54→    }
55→}
