 13→/// WASM-accessible CPU wrapper backed by EmulatorCore
 14→#[wasm_bindgen]
 15→#[derive(Clone)]
 16→pub struct WasmCpu {
 17→    emu: EmulatorCore,
 18→    last_result: Option<AssemblyResult>,
 19→}
 20→
 21→impl Default for WasmCpu {
 22→    fn default() -> Self {
 23→        Self::new()
 24→    }
 25→}
 26→
 27→#[wasm_bindgen]
 28→impl WasmCpu {
 29→    /// Create a new CPU
 30→    #[wasm_bindgen(constructor)]
 31→    pub fn new() -> Self {
 32→        console_error_panic_hook::set_once();
 33→        Self {
 34→            emu: EmulatorCore::new(),
 35→            last_result: None,
 36→        }
 37→    }
 38→
 39→    /// Reset the CPU to initial state (preserves memory)
 40→    pub fn reset(&mut self) {
 41→        self.emu.reset();
 42→    }
 43→
 44→    /// Hard reset - clears memory too
 45→    pub fn hard_reset(&mut self) {
 46→        self.emu.hard_reset();
 47→        self.last_result = None;
 48→    }
 49→
 50→    /// Assemble source code and load into memory
 51→    pub fn assemble(&mut self, source: &str) -> Result<JsValue, JsValue> {
 52→        let mut assembler = Assembler::new();
 53→        let result = assembler.assemble(source);
 54→
 55→        if result.errors.is_empty() {
 56→            self.emu.hard_reset();
 57→            // Load bytes at their correct addresses, tracking program extent
 58→            let mut highest_addr: u32 = 0;
 59→            for line in &result.lines {
 60→                for (i, &b) in line.bytes.iter().enumerate() {
 61→                    let addr = line.address + i as u32;
 62→                    self.emu.write_byte(addr, b);
 63→                    if addr + 1 > highest_addr {
 64→                        highest_addr = addr + 1;
 65→                    }
 66→                }
 67→            }
 68→            // Use load_program with empty slice to set program_end correctly
 69→            self.emu.load_program_extent(highest_addr);
 70→
 71→            console::log_1(&JsValue::from_str(&format!(
 72→                "Loaded {} bytes into memory",
 73→                result.bytes.len()
 74→            )));
 75→
 76→            self.last_result = Some(result.clone());
 77→            serde_wasm_bindgen::to_value(&result).map_err(|e| JsValue::from_str(&e.to_string()))
 78→        } else {
 79→            Err(JsValue::from_str(&result.errors.join("\n")))
 80→        }
 81→    }
 82→
 83→    /// Get the assembled lines for display
 84→    pub fn get_assembled_lines(&self) -> Vec<String> {
 85→        if let Some(result) = &self.last_result {
 86→            result
 87→                .lines
 88→                .iter()
 89→                .map(|line| {
 90→                    if line.bytes.is_empty() {
 91→                        format!("       {}", line.source)
 92→                    } else {
 93→                        let bytes_str: String = line
 94→                            .bytes
 95→                            .iter()
 96→                            .map(|b| format!("{:02X}", b))
 97→                            .collect::<Vec<_>>()
 98→                            .join(" ");
 99→                        format!("{:04X}: {:12} {}", line.address, bytes_str, line.source)
100→                    }
101→                })
102→                .collect()
103→        } else {
104→            Vec::new()
105→        }
106→    }
107→
108→    /// Execute one instruction
109→    pub fn step(&mut self) -> Result<bool, JsValue> {
110→        let result = self.emu.step();
111→        match result.reason {
112→            crate::emulator::StopReason::CycleLimit => Ok(true),
113→            crate::emulator::StopReason::Halted => Ok(false),
114→            crate::emulator::StopReason::InvalidInstruction(byte) => Err(JsValue::from_str(
115→                &format!("Invalid instruction: 0x{:02X}", byte),
116→            )),
117→            _ => Ok(true),
118→        }
119→    }
120→
121→    /// Run a batch of instructions (for animated execution)
122→    pub fn run_batch(&mut self, max_instructions: u32) -> bool {
123→        self.emu.resume();
124→        let result = self.emu.run_batch(max_instructions as u64);
125→        !matches!(result.reason, crate::emulator::StopReason::Halted | crate::emulator::StopReason::InvalidInstruction(_))
126→    }
127→
128→    /// Run until halt or error
129→    pub fn run(&mut self) -> Result<(), JsValue> {
130→        self.emu.resume();
131→        let result = self.emu.run_batch(100_000);
132→        match result.reason {
133→            crate::emulator::StopReason::CycleLimit
134→            | crate::emulator::StopReason::Halted
135→            | crate::emulator::StopReason::Paused
136→            | crate::emulator::StopReason::Breakpoint(_) => Ok(()),
137→            crate::emulator::StopReason::InvalidInstruction(byte) => Err(JsValue::from_str(
138→                &format!("Invalid instruction: 0x{:02X}", byte),
139→            )),
140→        }
141→    }
