279→    /// Get sparse SRAM representation: full 1MB region, only non-zero 16-byte rows included.
280→    pub fn get_sparse_sram(&self) -> components::SparseMemory {
281→        components::SparseMemory::from_slice(self.emu.sram(), 0x000000)
282→    }
