284→    /// Get sparse EBR/Stack representation: 0xFEE000–0xFEEC00 (3 KB usable stack area).
285→    pub fn get_sparse_ebr(&self) -> components::SparseMemory {
286→        let ebr = self.emu.ebr();
287→        // EBR is mapped at 0xFEE000. Stack area is 0xFEE000–0xFEEC00 (3072 bytes).
288→        let stack_size = 0xC00.min(ebr.len()); // 3 KB
289→        components::SparseMemory::from_slice(&ebr[..stack_size], 0xFEE000)
290→    }
291→}
