301→/// Validate a solution for a challenge
302→#[wasm_bindgen]
303→pub fn validate_challenge(challenge_id: usize, source: &str) -> Result<bool, JsValue> {
304→    let challenges = get_challenges();
305→    let challenge = challenges
306→        .iter()
307→        .find(|c| c.id == challenge_id)
308→        .ok_or_else(|| JsValue::from_str(&format!("Challenge {} not found", challenge_id)))?;
309→
310→    let mut assembler = Assembler::new();
311→    let result = assembler.assemble(source);
312→
313→    if !result.errors.is_empty() {
314→        return Err(JsValue::from_str(&result.errors.join("\n")));
315→    }
316→
317→    let mut cpu = CpuState::new();
318→    cpu.load_program(0, &result.bytes);
319→
320→    let executor = Executor::new();
321→    match executor.run(&mut cpu, 100000) {
322→        ExecuteResult::Ok | ExecuteResult::Halted => Ok((challenge.validator)(&cpu)),
323→        ExecuteResult::InvalidInstruction(byte) => Err(JsValue::from_str(&format!(
324→            "Invalid instruction: 0x{:02X}",
325→            byte
326→        ))),
327→        ExecuteResult::MemoryError(addr) => Err(JsValue::from_str(&format!(
328→            "Memory error at address: 0x{:06X}",
329→            addr
330→        ))),
331→    }
332→}
